patches.patch:
diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..0cca8887f 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1981,6 +1981,8 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 	fz_try(ctx)
 	{
 		pixmap = fz_get_pixmap_from_image(ctx, image, &src_area, &local_ctm, &dx, &dy);
+		if (pixmap == NULL)
+			return;

 		state[1].mask = fz_new_pixmap_with_bbox(ctx, NULL, bbox, NULL, 1);
 		fz_clear_pixmap(ctx, state[1].mask);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..cc7617db8 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1834,8 +1834,10 @@ fz_draw_fill_image(fz_context *ctx, fz_device *devp, fz_image *image, fz_matrix
 		if (state->blendmode & FZ_BLEND_KNOCKOUT)
 			fz_knockout_end(ctx, dev);
 	}
-	fz_always(ctx)
-		fz_drop_pixmap(ctx, pixmap);
+	fz_always(ctx) {
+		if (pixmap != scaled)
+			fz_drop_pixmap(ctx, pixmap);
+	}
 	fz_catch(ctx)
 		fz_rethrow(ctx);
 }

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..efd479ec7 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2030,7 +2030,8 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 			fz_dump_blend(ctx, "/GA=", state[1].group_alpha);
 #endif

-		fz_paint_image(ctx, state[1].mask, &bbox, state[1].shape, state[1].group_alpha, pixmap, local_ctm, 255, !(devp->hints & FZ_DONT_INTERPOLATE_IMAGES), 0);
+		if (pixmap)
+			fz_paint_image(ctx, state[1].mask, &bbox, state[1].shape, state[1].group_alpha, pixmap, local_ctm, 255, !(devp->hints & FZ_DONT_INTERPOLATE_IMAGES), 0);

 #ifdef DUMP_GROUP_BLENDS
 		fz_dump_blend(ctx, " to get ", state[1].mask);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..f69566568 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1981,6 +1981,8 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 	fz_try(ctx)
 	{
 		pixmap = fz_get_pixmap_from_image(ctx, image, &src_area, &local_ctm, &dx, &dy);
+		if (!pixmap)
+			return;

 		state[1].mask = fz_new_pixmap_with_bbox(ctx, NULL, bbox, NULL, 1);
 		fz_clear_pixmap(ctx, state[1].mask);
@@ -2001,7 +2003,7 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 		state[1].blendmode |= FZ_BLEND_ISOLATED;
 		state[1].scissor = bbox;

-		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
+		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && pixmap && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
 		{
 			int gridfit = !(dev->flags & FZ_DRAWDEV_FLAGS_TYPE3);
 			scaled = fz_transform_pixmap(ctx, dev, pixmap, &local_ctm, state->dest->x, state->dest->y, dx, dy, gridfit, &clip);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..ae09f4f53 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2022,7 +2022,10 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma

 #ifdef DUMP_GROUP_BLENDS
 		dump_spaces(dev->top, "");
-		fz_dump_blend(ctx, "Creating imagemask: plotting ", pixmap);
+		if (pixmap)
+			fz_dump_blend(ctx, "Creating imagemask: plotting ", pixmap);
+		else
+			fz_dump_blend(ctx, "Creating imagemask: plotting ", NULL);
 		fz_dump_blend(ctx, " onto ", state[1].mask);
 		if (state[1].shape)
 			fz_dump_blend(ctx, "/S=", state[1].shape);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..9674b9416 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2030,7 +2030,8 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 			fz_dump_blend(ctx, "/GA=", state[1].group_alpha);
 #endif

-		fz_paint_image(ctx, state[1].mask, &bbox, state[1].shape, state[1].group_alpha, pixmap, local_ctm, 255, !(devp->hints & FZ_DONT_INTERPOLATE_IMAGES), 0);
+		if (state[1].mask)
+			fz_paint_image(ctx, state[1].mask, &bbox, state[1].shape, state[1].group_alpha, pixmap, local_ctm, 255, !(devp->hints & FZ_DONT_INTERPOLATE_IMAGES), 0);

 #ifdef DUMP_GROUP_BLENDS
 		fz_dump_blend(ctx, " to get ", state[1].mask);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..d3d83df92 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1835,7 +1835,11 @@ fz_draw_fill_image(fz_context *ctx, fz_device *devp, fz_image *image, fz_matrix
 			fz_knockout_end(ctx, dev);
 	}
 	fz_always(ctx)
-		fz_drop_pixmap(ctx, pixmap);
+	{
+		if (pixmap != NULL)
+			fz_drop_pixmap(ctx, pixmap);
+		pixmap = NULL;
+	}
 	fz_catch(ctx)
 		fz_rethrow(ctx);
 }

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..e68a044cb 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2001,13 +2001,16 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 		state[1].blendmode |= FZ_BLEND_ISOLATED;
 		state[1].scissor = bbox;

-		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
-		{
-			int gridfit = !(dev->flags & FZ_DRAWDEV_FLAGS_TYPE3);
-			scaled = fz_transform_pixmap(ctx, dev, pixmap, &local_ctm, state->dest->x, state->dest->y, dx, dy, gridfit, &clip);
-			if (!scaled)
+		if (pixmap) {
+			int pw = pixmap->w;
+			int ph = pixmap->h;
+			if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pw, ph))
 			{
-				if (dx < 1)
+				int gridfit = !(dev->flags & FZ_DRAWDEV_FLAGS_TYPE3);
+				scaled = fz_transform_pixmap(ctx, dev, pixmap, &local_ctm, state->dest->x, state->dest->y, dx, dy, gridfit, &clip);
+				if (!scaled)
+				{
+					if (dx < 1)
 					dx = 1;
 				if (dy < 1)
 					dy = 1;

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..a05f6d2b8 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2018,6 +2018,12 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 				fz_drop_pixmap(ctx, pixmap);
 				pixmap = scaled;
 			}
+			else
+			{
+				// If scaling failed and no pixmap exists, we cannot proceed
+				if (!pixmap)
+					fz_throw(ctx, FZ_ERROR_GENERIC, "failed to obtain pixmap for image mask");
+			}
 		}

 #ifdef DUMP_GROUP_BLENDS

